import { Outlet, NavLink } from 'react-router-dom';

function DashboardLayout() {
  return (
    <div className="flex h-screen">
      {/* Sidebar — fixa, nunca muda */}
      <aside className="w-64 border-r bg-slate-800 p-4">
        <h2 className="text-lg font-bold text-white">Dashboard</h2>
        <nav className="mt-4 space-y-2">
          <NavLink to="/dashboard" end
            className={({ isActive }) =>
              isActive ? 'text-blue-400' : 'text-gray-400'
            }
          >
            Visão geral
          </NavLink>
          <NavLink to="/dashboard/analytics"
            className={({ isActive }) =>
              isActive ? 'text-blue-400' : 'text-gray-400'
            }
          >
            Analytics
          </NavLink>
          <NavLink to="/dashboard/settings"
            className={({ isActive }) =>
              isActive ? 'text-blue-400' : 'text-gray-400'
            }
          >
            Configurações
          </NavLink>
        </nav>
      </aside>

      {/* Conteúdo — muda conforme a rota filha */}
      <main className="flex-1 overflow-auto p-6">
        <Outlet />  {/* ← aqui renderiza a rota filha ativa */}
      </main>
    </div>
  );
}

const router = createBrowserRouter([
  {
    path: '/dashboard',
    element: <DashboardLayout />,  // layout pai
    children: [
      { index: true, element: <Overview /> },       // /dashboard
      { path: 'analytics', element: <Analytics /> }, // /dashboard/analytics
      { path: 'settings', element: <Settings /> },   // /dashboard/settings
    ],
  },
]);

{
  path: 'settings',
  element: <SettingsLayout />,  // layout com tabs
  children: [
    { index: true, element: <SettingsProfile /> },
    { path: 'security', element: <SettingsSecurity /> },
    { path: 'notifications', element: <SettingsNotifications /> },
  ],
}

const router = createBrowserRouter([
  {
    element: <AppLayout />,  // sem path → layout puro
    children: [
      { path: '/', element: <Home /> },
      { path: '/about', element: <About /> },
      { path: '/pricing', element: <Pricing /> },
    ],
  },
]);
